generated_oml:
// acting components: lighting and HVAC controllers
instance LightingActuator : DTDFVocab:ActingComponent [
    base:desc "Actuator controlling individual lighting fixtures within the campus laboratory building, defined in the BIM model."
]
instance HVACController : DTDFVocab:ActingComponent [
    base:desc "Controller managing HVAC setpoints for the building based on sensor data, defined in the BIM model."
]

// sensing components: environmental and occupancy sensors
instance TemperatureSensor : DTDFVocab:SensingComponent [
    base:desc "Environmental sensor measuring indoor air temperature as modeled in BIM and reporting post-occupancy data."
    DTDFVocab:producedData TemperatureDataTransmitted
]
instance LightLevelSensor : DTDFVocab:SensingComponent [
    base:desc "Environmental sensor measuring indoor illuminance levels in the building model."
    DTDFVocab:producedData LightLevelDataTransmitted
]
instance CO2Sensor : DTDFVocab:SensingComponent [
    base:desc "Environmental sensor measuring indoor CO₂ concentration inside the campus laboratory building."
    DTDFVocab:producedData CO2DataTransmitted
]
instance OccupancySensor : DTDFVocab:SensingComponent [
    base:desc "Occupancy sensor detecting presence of people in rooms, modeled in BIM."
    DTDFVocab:producedData OccupancyDataTransmitted
]

// physical-to-virtual interaction: data transmissions via Eclipse Hono
instance TemperatureDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TemperatureSensor
    base:desc "Temperature measurement message published by Eclipse Hono to the Ditto twin."
]
instance LightLevelDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom LightLevelSensor
    base:desc "Illuminance measurement message published by Eclipse Hono."
]
instance CO2DataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CO2Sensor
    base:desc "CO₂ concentration message published via Eclipse Hono."
]
instance OccupancyDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OccupancySensor
    base:desc "Occupancy data message forwarded by Eclipse Hono."
]

// data instances derived from transmitted data
instance TemperatureData : DTDFVocab:Data [
    base:desc "Actual temperature measurement value extracted from the temperature sensor."
    DTDFVocab:fromData TemperatureDataTransmitted
    DTDFVocab:inputTo DittoRegistry, ReinforcementLearningEngine
]
instance LightLevelData : DTDFVocab:Data [
    base:desc "Measured illuminance level value extracted from the light level sensor."
    DTDFVocab:fromData LightLevelDataTransmitted
    DTDFVocab:inputTo DittoRegistry, ReinforcementLearningEngine
]
instance CO2Data : DTDFVocab:Data [
    base:desc "Measured CO₂ concentration value extracted from the sensor."
    DTDFVocab:fromData CO2DataTransmitted
    DTDFVocab:inputTo DittoRegistry, ReinforcementLearningEngine
]
instance OccupancyData : DTDFVocab:Data [
    base:desc "Occupancy status value extracted from the occupancy sensor."
    DTDFVocab:fromData OccupancyDataTransmitted
    DTDFVocab:inputTo DittoRegistry, ReinforcementLearningEngine
]

// models and data: static BIM model and live sensor streams
instance StaticBIMModel : DTDFVocab:Model [
    base:desc "Static BIM information containing geometry, topology, semantics of the campus laboratory building."
    DTDFVocab:inputTo HonoGateway, DittoRegistry, BIMTransformationPipeline
]
instance DynamicSensorDataStream : DTDFVocab:Model [
    base:desc "Continuous live sensor data streams (temperature, light, CO₂, occupancy) feeding the Digital Twin."
    DTDFVocab:inputTo HonoGateway, DittoRegistry
]

// enablers
instance HonoGateway : DTDFVocab:Enabler [
    base:desc "Eclipse Hono IoT gateway routing sensor messages via MQTT to Ditto twins."
    DTDFVocab:enables DittoRegistry
]
instance DittoRegistry : DTDFVocab:Enabler [
    base:desc "Eclipse Ditto twin registry and state management for building components."
    DTDFVocab:enables RealTimeMonitoringService, LiveSimulationService, PredictiveAnalyticsService, FacilityManagementDecisionSupportService, ImmersiveVisualizationService
]
instance BIMTransformationPipeline : DTDFVocab:Enabler [
    base:desc "Model-driven deployment pipeline transforming enriched BIM into runtime artifacts using Eclipse Ditto configurator."
]
instance ReinforcementLearningEngine : DTDFVocab:Enabler [
    base:desc "Reinforcement learning engine optimizing lighting schedules and adjusting HVAC setpoints based on sensor data."
    DTDFVocab:enables LightingScheduleOptimizationService
]
instance UnrealVisualizationEngine : DTDFVocab:Enabler [
    base:desc "Unreal Engine 5 based immersive visualization engine rendering building model and performance data."
    DTDFVocab:enables ImmersiveVisualizationService
]

// services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Service providing real-time monitoring of building performance metrics such as temperature, light level, occupancy, and CO₂."
    DTDFVocab:provides RealTimeMonitoringInsight
]
instance LiveSimulationService : DTDFVocab:Service [
    base:desc "Service performing live simulation of building thermal performance based on real-time data."
    DTDFVocab:provides SimulationInsight
]
instance PredictiveAnalyticsService : DTDFVocab:Service [
    base:desc "Predictive analytics service forecasting energy consumption and visual comfort levels."
    DTDFVocab:provides EnergyConsumptionPredictionInsight, VisualComfortPredictionInsight
]
instance LightingScheduleOptimizationService : DTDFVocab:Service [
    base:desc "Service that optimizes lighting schedules via reinforcement learning based on sensor data."
    DTDFVocab:provides LightingScheduleOptimizationInsight, LightingScheduleUpdateAction
]
instance FacilityManagementDecisionSupportService : DTDFVocab:Service [
    base:desc "Decision support service for facility managers, providing actionable insights and HVAC adjustment recommendations."
    DTDFVocab:provides DecisionSupportInsight, HVACAdjustmentAction
]
instance ImmersiveVisualizationService : DTDFVocab:Service [
    base:desc "Immersive visualization service enabling real-time rendering of building and performance data in Unreal Engine 5."
    DTDFVocab:provides ImmersiveVisualizationInsight
]

// insights
instance RealTimeMonitoringInsight : DTDFVocab:Insight [
    base:desc "Real-time monitoring insight of indoor environment conditions."
]
instance SimulationInsight : DTDFVocab:Insight [
    base:desc "Insight from live simulation of building thermal performance."
]
instance EnergyConsumptionPredictionInsight : DTDFVocab:Insight [
    base:desc "Prediction of building energy consumption based on sensor data."
]
instance VisualComfortPredictionInsight : DTDFVocab:Insight [
    base:desc "Prediction of visual comfort levels (lighting and thermal) in the building."
]
instance LightingScheduleOptimizationInsight : DTDFVocab:Insight [
    base:desc "Insight into optimized lighting schedule derived from reinforcement learning."
]
instance DecisionSupportInsight : DTDFVocab:Insight [
    base:desc "Decision support insight for facility managers to adjust HVAC and lighting."
]
instance ImmersiveVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight into immersive visual representation of building performance."
]

// actions
instance LightingScheduleUpdateAction : DTDFVocab:Action [
    base:desc "Action to update lighting schedule via Ditto twin command."
    DTDFVocab:IsAutomatic true
]
instance HVACAdjustmentAction : DTDFVocab:Action [
    base:desc "Action to adjust HVAC setpoints based on predictive analytics."
    DTDFVocab:IsAutomatic false
]

// environment and components
instance BuildingEnvironment : DTDFVocab:Environment [
    base:contains ArchitecturalComponent, StructuralComponent, MechanicalComponent, ElectricalComponent, LightingComponent, SensorNetworkComponent, ActuatorNetworkComponent, TwinOrchestratorComponent
]

instance ArchitecturalComponent : DTDFVocab:Component [
    base:desc "Architectural elements of the campus laboratory building."
]
instance StructuralComponent : DTDFVocab:Component [
    base:desc "Structural framework of the building modeled in BIM."
]
instance MechanicalComponent : DTDFVocab:Component [
    base:desc "Mechanical systems including HVAC components."
]
instance ElectricalComponent : DTDFVocab:Component [
    base:desc "Electrical distribution and lighting controls."
]
instance LightingComponent : DTDFVocab:Component [
    base:desc "Lighting system comprising fixtures and controls."
]
instance SensorNetworkComponent : DTDFVocab:Component [
    base:desc "Network of environmental and occupancy sensors integrated in the building."
]
instance ActuatorNetworkComponent : DTDFVocab:Component [
    base:desc "Network of actuators and controllers for lighting and HVAC."
]
instance TwinOrchestratorComponent : DTDFVocab:Component [
    base:desc "Digital Twin orchestrator coordinating device twins and building-level services."
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Control commands generated by the Digital Twin are written to Ditto Things and routed by Hono over MQTT/TLS to the building’s controllers, enabling actuators to adjust lighting and other parameters."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time synchronization; sensor data and control messages are streamed instantly as event payloads, enabling live interaction between physical and virtual models."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A modular, service‑oriented architecture where individual device twins exchange information via Hono/Ditto under a central DT orchestrator, enabling extensibility and scalability."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (BIM creation), construction (model validation), commissioning (integration of IoT devices), and operation (runtime execution and iterative optimization). The DT spans the full life‑cycle of the building, from model to operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Evaluation with the Overall Digital Twin Entanglement (ODTE) metric to quantify the closeness of the digital twin to its physical counterpart; verification of sensor data integrity and semantic consistency is performed during model validation."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Real‑time communication implemented through the Eclipse Hono broker and Ditto twin registry, enabling bidirectional data exchange between the physical assets and the virtual twin."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of BIM as the semantically rich standard for building information, and adherence to standardized integration frameworks for DT deployment."
]
